function defaultLinkType(){const e=getUrlVars(window.location.href).a||localStorage.linktype||"link",t=document.querySelector(`.link-type li[data-label="${e}"]`),n=document.querySelector(".link-type input");t.classList.add("active"),n.value=e}function defaultEncoding(){const e=localStorage.encoding||"base64",t=document.querySelector('dropmenu[data-type="encoding"]'),n=t.querySelector("input"),o=t.querySelector(`li[data-option="${e}"]`);t.querySelector(".value").textContent=o.querySelector("span").textContent,n.value=e,o.classList.add("active")}function defaultShortening(){const e=localStorage.shortening||"isgd",t=document.querySelector('dropmenu[data-type="shortening"]'),n=t.querySelector("input"),o=t.querySelector(`li[data-option="${e}"]`);t.querySelector(".value").textContent=o.querySelector("span").textContent,n.value=e,o.classList.add("active")}function setDefaults(){try{defaultLinkType()}catch{}try{defaultEncoding()}catch{}try{defaultShortening()}catch{}}setDefaults();